    StatusInactive = "inactive"
    StatusPending  = "pending"
)

// iota（自動遞增、用於 enum-like）
const (
    Sunday = iota   // 0
    Monday          // 1
    Tuesday         // 2
    Wednesday       // 3
    // ...
)

// 位元運算
const (
    Read    = 1 
