lessons.content:
Go 函數有幾個特別功能—多回傳值（特別配 error）、命名回傳、變參。


### 基本函數

```text
// 格式：func 名字(參數) 回傳型別 { body }

func add(a int, b int) int {
    return a + b
}

// 同型別參數可省略
func add(a, b int) int {
    return a + b
}

// 沒回傳
func greet(name string) {
    fmt.Println("Hello,", name)
}

// 多參數
func createUser(name string, age int, email string) {
    // ...
}

// 用
result := add(2, 3)
greet("Alice")
```


### 多回傳值（Go 特色）

```text
// Go 慣用 pattern：回 (result, error)
func divide(a, b int) (int, error) {
    if b == 0 {
        return 0, errors.New("division by zero")
    }
    return a / b, nil
}

// 用
result, err := divide(10, 2)
if err != nil {
    log.Fatal(err)
}
fmt.Println(result)

// 忽略某個值用 _
result, _ := divide(10, 2)
_, err := divide(10, 2)

// 多回傳值（不只 2 個）
func stats(nums []int) (min, max, avg int) {
    // ...
}

min, max, avg := stats([]int{1, 2, 3})
```


### 命名回傳值（naked return）

```text
// 在 signature 命名回傳變數
func stats(nums []int) (min, max, sum int) {
    // min, max, sum 已宣告（零值 0）

    if len(nums) == 0 {
        return    // naked return、回 (0, 0, 0)
    }

    min = nums[0]
    max = nums[0]

    for _, n := range nums {
        if n  max { max = n }
        sum += n
    }

    return    // 自動回 (min, max, sum)
}

// 適合：短函數
// 不適合：長函數（看不出回什麼、難讀）

// 常用 pattern：error 命名回傳 + defer 改
func readConfig() (config *Config, err error) {
    defer func() {
        if r := recover(); r != nil {
            err = fmt.Errorf("recovered: %v", r)
        }
    }()

    // 跑可能 panic 的 code
    return
}
```


### 變參（Variadic）

```text
// ...type 表示變參
func sum(nums ...int) int {
    total := 0
    for _, n := range nums {
        total += n
    }
    return total
}

// 用
sum(1, 2, 3)         // 6
sum(1, 2, 3, 4, 5)   // 15
sum()                // 0

// 傳 slice 用 ...
nums := []int{1, 2, 3}
sum(nums...)         // 展開 slice

// 經典：fmt.Println
fmt.Println("a", "b", "c", 123)
// fmt.Println(values ...interface{})

// 自己寫 logger
func logf(level string, format string, args ...interface{}) {
    msg := fmt.Sprintf(format, args...)
    fmt.Printf("[%s] %s\n", level, msg)
}

logf("INFO", "User %s logged in from %s", "Alice", "1.2.3.4")
```


### 函數是 first-class（一等公民）

```text
// 函數能傳 / 回 / 存

// 1. 存變數
add := func(a, b int) int {
    return a + b
}
result := add(2, 3)

// 2. 當參數
func operate(a, b int, op func(int, int) int) int {
    return op(a, b)
}

sum := operate(2, 3, add)
product := operate(2, 3, func(a, b int) int {
    return a * b
})

// 3. 回傳函數
func multiplier(factor int) func(int) int {
    return func(x int) int {
        return x * factor
    }
}

double := multiplier(2)
triple := multiplier(3)
double(5)    // 10
triple(5)    // 15

// 4. Closure（閉包）
func counter() func() int {
    count := 0
    return func() int {
        count++
        return count
    }
}

c := counter()
c()    // 1
c()    // 2
c()    // 3
```


### 方法（method）

```text
// 方法 = 帶 receiver 的函數
type Rectangle struct {
    Width, Height float64
}

// receiver: r Rectangle
func (r Rectangle) Area() float64 {
    return r.Width * r.Height
}

// 用
rect := Rectangle{Width: 3, Height: 4}
fmt.Println(rect.Area())    // 12

// Receiver 兩種：
// 1. 值 receiver（不改 struct）
func (r Rectangle) Area() float64 { ... }

// 2. 指標 receiver（能改 struct）
func (r *Rectangle) Scale(factor float64) {
    r.Width *= factor
    r.Height *= factor
}

rect.Scale(2)   // 改 rect

// 規則：
// - struct 大 / 要改 → 用指標 receiver
// - 簡單 struct / 不改 → 用值 receiver
// - 同一型別所有 method 風格一致

// 方法能加在任何型別（不只 struct）
type Celsius float64

func (c Celsius) ToFahrenheit() float64 {
    return float64(c)*9/5 + 32
}

temp := Celsius(25)
fmt.Println(temp.ToFahrenheit())   // 77
```


### 常見 pattern

```text
// 1. 錯誤鏈
func processOrder(id int) (*Order, error) {
    order, err := db.GetOrder(id)
    if err != nil {
        return nil, fmt.Errorf("get order: %w", err)
    }

    if err := order.Validate(); err != nil {
        return nil, fmt.Errorf("validate: %w", err)
    }

    if err := order.Process(); err != nil {
        return nil, fmt.Errorf("process: %w", err)
    }

    return order, nil
}

// 2. Options pattern（沒 named arg、用 functional options）
type ServerOption func(*Server)

func WithPort(port int) ServerOption {
    return func(s *Server) {
        s.Port = port
    }
}

func WithLogger(l Logger) ServerOption {
    return func(s *Server) {
        s.Logger = l
    }
}

func NewServer(opts ...ServerOption) *Server {
    s := &Server{Port: 8080}
    for _, opt := range opts {
        opt(s)
    }
    return s
}

// 用
server := NewServer(
    WithPort(3000),
    WithLogger(myLogger),
)

// 3. Builder pattern（用 fluent API）
func NewRequest() *RequestBuilder {
    return &RequestBuilder{...}
}

func (b *RequestBuilder) URL(url string) *RequestBuilder {
    b.url = url
    return b
}

req := NewRequest().URL("...").Header("Auth", "...").Build()
```


    **🚀 進階技巧**

Go 函數設計 5 心法：(1) **多回傳值搭 error**—`(result, error)` 是慣例 (2) **err 永遠最後一個**—maintain consistency (3) **short receiver name**—`func (r Rectangle)`、不是 `(rect Rectangle)` (4) **不要 named return**（除非真的有幫助） (5) **function options pattern**—Go 沒 named arg、用 options 取代。





      🚀
      2026 趨勢

    這個技術 2026 還在主流、未來 5 年不會過時。**但工具會更新**—訂閱 1-2 個技術頻道（如 Theo / Fireship / Web Dev Simplified），每月花 30 分鐘看新東西就夠跟上潮流。AI 時代學習法：不背、會查、會用 ChatGPT / Claude 問。

