### Composition（組合）—取代繼承

```text
// Go 沒 extends / inheritance
// 用 embedding（嵌入）做「組合」

type Animal struct {
    Name string
    Age  int
}

func (a Animal) Eat() {
    fmt.Println(a.Name, "在吃")
}

type Dog struct {
    Animal       // embed（嵌入）
    Breed string
}

// Dog 自動有 Animal 的欄位 + 方法
d := Dog{
    Animal: Animal{Name: "Lucky", Age: 3},
    Breed:  "Shiba",
}

fmt.Println(d.Name)    // "Lucky"（自動取 embedded）
d.Eat()                // "Lucky 在吃"

// 加自己的方法
func (d Dog) Bark() {
    fmt.Println(d.Name, "汪汪")
}

d.Bark()

// 覆寫
func (d Dog) Eat() {
    fmt.Println(d.Name, "啃骨頭")
}

d.Eat()             // "Lucky 啃骨頭"（自己的版本）
d.Animal.Eat()      // "Lucky 在吃"（明確叫父）

// 比繼承彈性：
// - 一個 struct 能 embed 多個
// - 沒「is-a」、是「has-a」
// - 不會有 diamond problem
```


### Tag：給 struct 加 metadata

```text
// Tag 是字串、給其他工具讀
type User struct {
    ID    int    `json:"id" db:"user_id"`
    Name  string `json:"name" validate:"required,min=3"`
    Email string `json:"email" validate:"required,email"`
    Age   int    `json:"age,omitempty"`
}

// json 套件（標準庫）會讀
import "encoding/json"

u := User{ID: 1, Name: "Alice", Email: "alice@x.com"}
data, _ := json.Marshal(u)
fmt.Println(string(data))
// {"id":1,"name":"Alice","email":"alice@x.com"}
// 沒 Age（因為 omitempty + 是零值）

// 反向（unmarshal）
var u User
json.Unmarshal([]byte(`{"id":1,"name":"Alice"}`), &u)
// u.Name = "Alice"

// 驗證套件（go-playground/validator）會讀 validate tag
import "github.com/go-playground/validator/v10"

v := validator.New()
err := v.Struct(u)
if err != nil { ... }

// DB（如 sqlx）會讀 db tag
db.Get(&u, "SELECT * FROM users WHERE id=?", 1)
```


### 實戰：完整 User 模型

```text
package user

import (
    "errors"
    "time"
)

type User struct {
    ID        int       `json:"id"`
    Name      string    `json:"name"`
    Email     string    `json:"email"`
    Password  string    `json:"-"`             // - 不 marshal
    Role      string    `json:"role"`
    CreatedAt time.Time `json:"created_at"`
    UpdatedAt time.Time `json:"updated_at"`
}

// Constructor
func New(name, email, password string) (*User, error) {
    if name == "" {
        return nil, errors.New("name required")
    }

    return &User{
        Name:      name,
        Email:     email,
        Password:  hashPassword(password),
        Role:      "user",
        CreatedAt: time.Now(),
        UpdatedAt: time.Now(),
    }, nil
}

// Method
func (u *User) IsAdmin() bool {
    return u.Role == "admin"
}

func (u *User) UpdateEmail(email string) error {
    if !isValidEmail(email) {
        return errors.New("invalid email")
    }
    u.Email = email
    u.UpdatedAt = time.Now()
    return nil
}

func (u *User) VerifyPassword(plain string) bool {
    return verifyHash(plain, u.Password)
}

// 用
u, err := user.New("Alice", "alice@x.com", "secret")
if err != nil { ... }

if u.IsAdmin() {
    fmt.Println("admin")
}

u.UpdateEmail("alice@new.com")
