Go 有指標（pointer）—但沒 C 的指標運算（沒 `p++`），用起來更安全。


### 什麼是指標

```text
// 變數 = 值 + 地址
x := 42

// & 取地址
p := &x
fmt.Println(p)    // 0xc000018030（記憶體地址）

// * 解引用（拿值）
fmt.Println(*p)   // 42

// 改地址的值
*p = 100
fmt.Println(x)    // 100

// 函數參數：值傳 vs 指標傳
func increment(n int) {
    n++       // 改 local copy、不影響外面
}

func incrementPtr(n *int) {
    *n++      // 改外面的值
}

x := 5
increment(x)
fmt.Println(x)    // 5（沒變）

incrementPtr(&x)
fmt.Println(x)    // 6
```


### 指標 vs 值 傳遞

```text
// Go 預設值傳（copy）
// slice / map / channel 是「引用型別」、傳的是底層指標

// Struct（值傳）
type User struct {
    Name string
}

func modify(u User) {
    u.Name = "Bob"     // 改 copy、不影響原本
}

u := User{Name: "Alice"}
modify(u)
fmt.Println(u.Name)    // "Alice"

// 用指標
func modifyPtr(u *User) {
    u.Name = "Bob"     // 改原本
}

modifyPtr(&u)
fmt.Println(u.Name)    // "Bob"

// Slice（特殊：底層是指標）
func modifySlice(s []int) {
    s[0] = 99       // 改底層 array、外面看得到
}

nums := []int{1, 2, 3}
modifySlice(nums)
fmt.Println(nums)    // [99 2 3]

// 但 append 可能不影響（看 cap）
func appendSlice(s []int) {
    s = append(s, 99)    // 可能建新底層 array
}

appendSlice(nums)
fmt.Println(nums)    // [99 2 3]（append 沒影響）

// Map（引用型別、直接傳）
func modifyMap(m map[string]int) {
    m["new"] = 999
}

m := map[string]int{"a": 1}
modifyMap(m)
fmt.Println(m)    // {a: 1, new: 999}
```


