Go 的 interface 是**隱式實作**—不用 `implements`、有方法就算。這是 Go 的設計精華。


### 基本 interface

```text
// 定義 interface
type Animal interface {
    Speak() string
}

// struct 不用宣告 implements
// 有 Speak() 就算實作 Animal
type Dog struct {
    Name string
}

func (d Dog) Speak() string {
    return d.Name + " 汪汪"
}

type Cat struct {
    Name string
}

func (c Cat) Speak() string {
    return c.Name + " 喵喵"
}

// 用 interface 為型別
func describe(a Animal) {
    fmt.Println(a.Speak())
}

describe(Dog{Name: "Lucky"})    // Lucky 汪汪
describe(Cat{Name: "Mimi"})     // Mimi 喵喵

// Go 不要求 "implements"！
// 「Duck typing」：走起來像鴨、叫起來像鴨、就是鴨
```


### 標準庫 interface

```text
// fmt.Stringer：自訂 print 格式
type Stringer interface {
    String() string
}

type User struct {
    Name string
    Age  int
}

func (u User) String() string {
    return fmt.Sprintf("User(%s, %d)", u.Name, u.Age)
}

u := User{Name: "Alice", Age: 30}
fmt.Println(u)    // User(Alice, 30)
// fmt 自動呼叫 String()

// error 是 interface！
type error interface {
    Error() string
}

// 自訂 error
type ValidationError struct {
    Field string
    Msg   string
}

func (e *ValidationError) Error() string {
    return fmt.Sprintf("%s: %s", e.Field, e.Msg)
}

// 用
err := &ValidationError{Field: "email", Msg: "invalid"}
fmt.Println(err)    // email: invalid

// io.Reader / io.Writer（無敵 interface）
type Reader interface {
    Read(p []byte) (n int, err error)
}

type Writer interface {
    Write(p []byte) (n int, err error)
}

// 任何「能讀的」都實作 Reader：
// - 檔案
// - 網路連線
// - 字串
// - HTTP body
// - bytes buffer

// 1 個函數能處理所有
func copyData(src io.Reader, dst io.Writer) error {
    _, err := io.Copy(dst, src)
    return err
}

// 用
file, _ := os.Open("input.txt")
defer file.Close()

dst, _ := os.Create("output.txt")
defer dst.Close()

copyData(file, dst)
// 換成 HTTP body / 字串都 work、不改函數
```


