### 常見 interface pattern

```text
// 1. 小 interface（ b {
        return a
    }
    return b
}

Max(3, 5)         // 5
Max(3.14, 2.71)   // 3.14
Max("b", "a")     // "b"

// 用 constraints package
import "golang.org/x/exp/constraints"

func Max[T constraints.Ordered](a, b T) T {
    if a > b {
        return a
    }
    return b
}

// 泛型 struct
type Stack[T any] struct {
    items []T
}

func (s *Stack[T]) Push(item T) {
    s.items = append(s.items, item)
}

func (s *Stack[T]) Pop() (T, bool) {
    var zero T
    if len(s.items) == 0 {
        return zero, false
    }
    last := s.items[len(s.items)-1]
    s.items = s.items[:len(s.items)-1]
    return last, true
}

// 用
intStack := &Stack[int]{}
intStack.Push(1)
intStack.Push(2)

stringStack := &Stack[string]{}
stringStack.Push("hello")

// 2026 趨勢：
// - interface 仍主流（duck typing）
// - 泛型用於 collection / utility
// - 別過度用（Go 哲學：簡單）
```


