Go 不用 try-catch—用 `error` 回傳值。看起來囉嗦、實際更明確。


### 基本：error 是 interface

```text
// 標準庫定義
type error interface {
    Error() string
}

// 任何有 Error() string 的型別 = error

// 建 error 3 種方式
import "errors"

// 1. errors.New
err := errors.New("something went wrong")

// 2. fmt.Errorf（含格式化）
err := fmt.Errorf("user %d not found", id)

// 3. 自訂 type
type NotFoundError struct {
    Resource string
    ID       int
}

func (e *NotFoundError) Error() string {
    return fmt.Sprintf("%s %d not found", e.Resource, e.ID)
}

err := &NotFoundError{Resource: "user", ID: 123}
```


### error 回傳 pattern

```text
// 慣例：error 永遠最後
func divide(a, b int) (int, error) {
    if b == 0 {
        return 0, errors.New("divide by zero")
    }
    return a / b, nil
}

// 用：先檢查 error
result, err := divide(10, 0)
if err != nil {
    log.Fatal(err)
    return
}
fmt.Println(result)

// 沒值的 error：只回 error
func saveUser(u *User) error {
    if u.Name == "" {
        return errors.New("name required")
    }
    return db.Save(u)
}

// 例外：bool（不該叫 error）
func contains(s []int, n int) bool {
    for _, v := range s {
        if v == n {
            return true
        }
    }
    return false
}
```


### 包裝 error（error wrapping）

```text
// 在錯誤上加 context、不丟原本
import "fmt"
import "errors"

func processOrder(id int) error {
    order, err := db.GetOrder(id)
    if err != nil {
        return fmt.Errorf("get order %d: %w", id, err)
        // %w 包裝 error
    }

    if err := order.Validate(); err != nil {
        return fmt.Errorf("validate order: %w", err)
    }

    return nil
}

// 抓特定 error 型別
err := processOrder(123)
if err != nil {
    var notFound *NotFoundError
    if errors.As(err, &notFound) {
        fmt.Println("Not found:", notFound.Resource)
    }
}

// 抓 sentinel error
var ErrNotFound = errors.New("not found")

err := getUser(id)
if errors.Is(err, ErrNotFound) {
    // 處理 not found
}

// 比較：
// errors.Is - 比對 sentinel error
// errors.As - 抓特定型別 error
```


### 實戰：層級錯誤

```text
// service layer
type UserService struct {
    repo UserRepository
}

func (s *UserService) Register(name, email string) (*User, error) {
    if email == "" {
        return nil, ErrEmailRequired
    }

    existing, err := s.repo.FindByEmail(email)
    if err != nil && !errors.Is(err, ErrNotFound) {
        return nil, fmt.Errorf("check existing: %w", err)
    }

    if existing != nil {
        return nil, ErrEmailTaken
    }

    user := &User{Name: name, Email: email}
    if err := s.repo.Save(user); err != nil {
        return nil, fmt.Errorf("save user: %w", err)
    }

    return user, nil
}

// API handler
func handleRegister(w http.ResponseWriter, r *http.Request) {
    user, err := service.Register(name, email)
    if err != nil {
        switch {
        case errors.Is(err, ErrEmailRequired):
            http.Error(w, "Email required", 400)
        case errors.Is(err, ErrEmailTaken):
            http.Error(w, "Email taken", 409)
        default:
            log.Printf("register error: %v", err)
            http.Error(w, "Internal error", 500)
        }
        return
    }

    json.NewEncoder(w).Encode(user)
}
```


### 常見 error 慣用法

```text
// 1. Sentinel errors（package 級別常數）
package user

var (
    ErrNotFound = errors.New("user not found")
    ErrEmailTaken = errors.New("email already taken")
    ErrInvalidPassword = errors.New("invalid password")
)

// 2. error type（含資料）
type ValidationError struct {
    Field   string
    Message string
}

func (e *ValidationError) Error() string {
    return fmt.Sprintf("%s: %s", e.Field, e.Message)
}

// 3. errors.Join（多錯誤、Go 1.20+）
err := errors.Join(err1, err2, err3)

// 4. 不要忽略 error
// ❌
result, _ := operation()    // 丟掉 error

// ✓
result, err := operation()
if err != nil {
    return err
}

// 例外：你真的不在乎
n, _ := strconv.Atoi("123")    // 從 user input 解析、有 default

// 5. defer 內的 error
func writeFile(name string, data []byte) (err error) {
    f, err := os.Create(name)
    if err != nil {
        return err
    }
    defer func() {
        if cerr := f.Close(); cerr != nil && err == nil {
            err = cerr
        }
    }()

    _, err = f.Write(data)
    return
}
```


### panic 跟 error 的差別

```text
error：可預期、能處理
- 檔案不存在
- DB 連線失敗
- 用戶輸入錯
- 網路 timeout

panic：不可恢復、程式 bug
- nil pointer dereference
- 越界 access
- 不可能的狀況（switch default 該到）

慣用：
- 函數 return error
- main / handler 不 panic
- middleware 用 recover 防止 server crash

// HTTP middleware
func recoverMiddleware(next http.Handler) http.Handler {
    return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
        defer func() {
            if err := recover(); err != nil {
                log.Printf("panic: %v\n%s", err, debug.Stack())
                http.Error(w, "Internal Server Error", 500)
            }
        }()
        next.ServeHTTP(w, r)
    })
}
```


### Error vs Exception 哲學

```text
Java / Python（exception）：
- 自動 propagate（往上拋）
- catch 才停
- 容易忘記處理

Go（error）：
- 每個函數明確處理
- 看 code 就知道哪會錯
- 寫起來囉嗦
- 但長期維護更穩

例：
// Java
try {
    user = getUser(id);
    order = createOrder(user);
} catch (Exception e) {
    log.error(e);
}

// Go
user, err := getUser(id)
if err != nil {
    return fmt.Errorf("get user: %w", err)
}

order, err := createOrder(user)
if err != nil {
    return fmt.Errorf("create order: %w", err)
}

// Go 多 30% 行數
// 但每處錯誤都明確處理
// production 穩定度高
```


    **☕ 用人話講**

Go error 4 心法：(1) **error 是回傳值**—不是丟出 (2) **永遠檢查 err != nil**—不要 _, _ 忽略 (3) **包裝錯誤加 context**—`fmt.Errorf("...: %w", err)` (4) **panic 只用於不可恢復 bug**—業務錯用 error。**初學覺得囉嗦、3 個月後愛上明確**。





