### Middleware：函數包函數

```text
// Middleware = 接受 handler、回 handler
func loggingMiddleware(next http.Handler) http.Handler {
    return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
        start := time.Now()
        log.Printf("%s %s", r.Method, r.URL.Path)

        next.ServeHTTP(w, r)

        log.Printf("%s %s done in %v", r.Method, r.URL.Path, time.Since(start))
    })
}

func authMiddleware(next http.Handler) http.Handler {
    return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
        token := r.Header.Get("Authorization")
        if token == "" {
            http.Error(w, "Unauthorized", 401)
            return
        }

        userID, err := verifyToken(token)
        if err != nil {
            http.Error(w, "Invalid token", 401)
            return
        }

        // 傳 userID 給下個 handler（context）
        ctx := context.WithValue(r.Context(), "userID", userID)
        next.ServeHTTP(w, r.WithContext(ctx))
    })
}

// 用：串接
mux := http.NewServeMux()
mux.HandleFunc("GET /me", meHandler)

// 包 middleware
handler := loggingMiddleware(authMiddleware(mux))
http.ListenAndServe(":8080", handler)

// 鏈式 helper
func chain(h http.Handler, middlewares ...func(http.Handler) http.Handler) http.Handler {
    for i := len(middlewares) - 1; i >= 0; i-- {
        h = middlewares[i](h)
    }
    return h
}

handler := chain(mux, loggingMiddleware, authMiddleware, corsMiddleware)
```


