db.First(&user, "email = ?", "alice@x.com")

var users []User
db.Find(&users)
db.Where("age > ?", 18).Find(&users)
db.Where("name LIKE ?", "%Alice%").Order("age DESC").Limit(10).Find(&users)

// Update
db.Model(&user).Update("Age", 31)
db.Model(&user).Updates(User{Age: 31, Name: "Alice Smith"})

// Delete（軟刪除、DeletedAt 設 timestamp）
db.Delete(&user, 1)

// 硬刪
db.Unscoped().Delete(&user, 1)

// Transactions
db.Transaction(func(tx *gorm.DB) error {
    if err := tx.Create(&user).Error; err != nil {
        return err
    }
    if err := tx.Create(&order).Error; err != nil {
        return err
    }
    return nil
})
