db.Joins("JOIN posts ON posts.user_id = users.id").
   Where("posts.title LIKE ?", "%Go%").
   Find(&users)

// Group / Aggregate
type Result struct {
    City string
    Total int
}
var results []Result
db.Model(&User{}).Select("city, count(*) as total").Group("city").Find(&results)

// Raw SQL（GORM 包不來時）
db.Raw("SELECT * FROM users WHERE age > ?", 18).Scan(&users)
db.Exec("UPDATE users SET status = ? WHERE id = ?", "active", 1)

// Hooks（生命週期）
func (u *User) BeforeCreate(tx *gorm.DB) error {
    u.Password = hashPassword(u.Password)
    return nil
}

func (u *User) AfterCreate(tx *gorm.DB) error {
    sendWelcomeEmail(u.Email)
    return nil
}
