### RBAC（角色權限）

```text
type User struct {
    ID   uint
    Role string    // "admin" / "user" / "viewer"
}

// 在 token 加 role
type Claims struct {
    UserID int
    Role   string
    jwt.RegisteredClaims
}

// Middleware：限 role
func RequireRole(roles ...string) gin.HandlerFunc {
    return func(c *gin.Context) {
        userRole := c.GetString("userRole")

        for _, r := range roles {
            if userRole == r {
                c.Next()
                return
            }
        }

        c.AbortWithStatusJSON(403, gin.H{"error": "forbidden"})
    }
}

// 用
admin := r.Group("/admin")
admin.Use(AuthMiddleware(), RequireRole("admin"))
{
    admin.DELETE("/users/:id", deleteUser)
    admin.POST("/products", createProduct)
}

editor := r.Group("/editor")
editor.Use(AuthMiddleware(), RequireRole("admin", "editor"))
{
    editor.PATCH("/posts/:id", updatePost)
}
```


### Refresh Token Pattern

```text
// Access token 短期（15 min）
// Refresh token 長期（30 天）+ 存 DB

type RefreshToken struct {
    Token     string `gorm:"primaryKey"`
    UserID    uint
    ExpiresAt time.Time
}

func createTokens(userID int, email string) (access, refresh string, err error) {
    // Access（短）
    access, err = createJWT(userID, email, 15*time.Minute)

    // Refresh（長、random string）
    refresh = generateRandomString(32)

    // 存 DB
    db.Create(&RefreshToken{
        Token:     refresh,
        UserID:    uint(userID),
        ExpiresAt: time.Now().Add(30 * 24 * time.Hour),
    })

    return
}

func refreshHandler(c *gin.Context) {
    var input struct {
        RefreshToken string `json:"refresh_token"`
    }
    c.ShouldBindJSON(&input)

    // 查 DB
    var rt RefreshToken
    if err := db.Where("token = ? AND expires_at > ?",
        input.RefreshToken, time.Now()).First(&rt).Error; err != nil {
        c.JSON(401, gin.H{"error": "invalid refresh token"})
        return
    }

    // 生新 access token
    var user User
    db.First(&user, rt.UserID)

    access, _ := createJWT(int(user.ID), user.Email, 15*time.Minute)
    c.JSON(200, gin.H{"access_token": access})
}

// 登出（撤銷 refresh token）
func logout(c *gin.Context) {
    var input struct {
        RefreshToken string `json:"refresh_token"`
    }
    c.ShouldBindJSON(&input)

    db.Where("token = ?", input.RefreshToken).Delete(&RefreshToken{})
    c.JSON(200, gin.H{"message": "logged out"})
}
```


