case msg := <-ch2:
    fmt.Println("ch2:", msg)
case <-time.After(1 * time.Second):
    fmt.Println("timeout")
}
```

## sync.WaitGroup
```go
var wg sync.WaitGroup

for i := 0; i < 10; i++ {
    wg.Add(1)
    go func(n int) {
        defer wg.Done()
        fmt.Println(n)
    }(i)
}
wg.Wait()  // 等所有結束
```

## Mutex（互斥鎖）
```go
var (
    counter int
    mu      sync.Mutex
)

func increment() {
    mu.Lock()
    defer mu.Unlock()
    counter++
}
```

## Worker Pool 模式
```go
func worker(id int, jobs <-chan int, results chan<- int) {
    for j := range jobs {
        result := j * 2
        results <- result
    }
}

func main() {
    jobs := make(chan int, 100)
    results := make(chan int, 100)

    // 開 3 個 worker
    for w := 1; w <= 3; w++ {
        go worker(w, jobs, results)
    }

    // 送 9 個 job
    for j := 1; j <= 9; j++ {
        jobs <- j
    }
    close(jobs)

    // 收結果
    for a := 1; a <= 9; a++ {
        <-results
    }
}
```

## Context：取消 + timeout
```go
ctx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
defer cancel()

select {
case <-ctx.Done():
    fmt.Println("timeout 或取消")
case result := <-ch:
    fmt.Println(result)
}
```

## 實戰：並發抓 100 個 URL
```go
func fetchAll(urls []string) []string {
    results := make([]string, len(urls))
    var wg sync.WaitGroup

    for i, url := range urls {
        wg.Add(1)
        go func(idx int, u string) {
            defer wg.Done()
            resp, err := http.Get(u)
            if err != nil { return }
            defer resp.Body.Close()
            body, _ := io.ReadAll(resp.Body)
            results[idx] = string(body)
        }(i, url)
    }
    wg.Wait()
    return results
}
```

## 注意事項
- ⚠️ goroutine leak：別忘了 close channel / 取消 context
- ⚠️ race condition：用 `go run -race` 偵測
- ⚠️ 多人寫同 map 要用 `sync.Map` 或 mutex

